const BeaconTrack={endpoint:null,defaultEvents:["click"],events:[],_lastSent:{},init(t={}){this.endpoint=t.endpoint||"/api/v1/stats/track/",this.events=t.events?[...this.defaultEvents,...t.events]:[...this.defaultEvents],this._bindClick(),this.events.forEach(t=>this._bindEvent(t)),this._bindPreInit()},track(t,e=null){const n=Date.now();if(this._lastSent[t]&&n-this._lastSent[t]<300)return;this._lastSent[t]=n;const a={event:t};null!==e&&(a.value=e);const s=new Blob([JSON.stringify(a)],{type:"application/json"});navigator.sendBeacon?navigator.sendBeacon(this.endpoint,s):fetch(this.endpoint,{method:"POST",body:s,keepalive:!0})},_getTrackData:t=>({key:t.dataset.track,value:t.dataset.trackValue||null}),_bindClick(){document.addEventListener("click",t=>{const e=t.target.closest("[data-track]:not([data-track-on])");if(!e)return;const{key:n,value:a}=this._getTrackData(e);this.track(n,a)})},_bindEvent(t){document.addEventListener(t,e=>{const n=e.target.closest(`[data-track-on="${t}"]`);if(!n)return;const{key:a,value:s}=this._getTrackData(n);this.track(a,s)})},_bindPreInit(){document.querySelectorAll("[data-track-init]").forEach(t=>{const e=t.dataset.trackInitValue||null;this.track(t.dataset.trackInit,e)})}};